// Pull enriched data from Enrich1 (stable ref regardless of attachment path)
const d = $('Parse Zoho LLM + Enrich3').first().json;
const slaConfigs = d._slaConfigs || [];
const priority = d._priority || 'P3';
const sla = slaConfigs.find(s => s.priority === priority) || {};
const responseHours = Number(sla.response_hours) || 8;
const resolutionHours = Number(sla.resolution_hours) || 24;

const now = new Date();
const slaResponseDue = new Date(now.getTime() + responseHours * 3600000).toISOString();
const slaResolutionDue = new Date(now.getTime() + resolutionHours * 3600000).toISOString();

const contactName = [d.contact?.firstName, d.contact?.lastName].filter(Boolean).join(' ') || '';

return [{
  json: {
    ...d,
    _insert: {
      company_id: d._companyId || null,
      solution_id: d._solutionId || null,
      title: (d.subject || d._summary || 'New Zoho Ticket').substring(0, 500),
      description: d._description || '',
      priority: priority,
      module: d._module || '',
      request_type: d._requestType || '',
      case_type: d._caseType || '',
      zoho_ticket_id: String(d.ticketNumber || d.id || ''),
      ai_summary: (d._summary || '').substring(0, 1000),
      ai_sentiment: d._sentiment || 'neutral',
      sla_response_due: slaResponseDue,
      sla_resolution_due: slaResolutionDue,
      created_by_email: d.contact?.email || '',
      created_by_name: contactName,
      created_at: d.createdTime || now.toISOString()
    }
  }
}];

/**
 * n8n Code node (JavaScript)
 * Input: Zoho Desk webhook payload from Webhook node
 * Output: Normalized object with key ticket + contact + thread + attachments fields
 */

function firstDefined(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return null;
}

function toIntMaybe(v) {
  if (v === null || v === undefined) return null;
  const n = parseInt(String(v), 10);
  return Number.isFinite(n) ? n : null;
}

function stripHtml(html) {
  if (!html) return null;
  return String(html)
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<\/?[^>]+(>|$)/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

// n8n provides `items` array
const item = items[0] || {};
const body = item.json?.body;

// Zoho sends body as an array of events: [ { payload, eventTime, eventType, orgId } ]
const evt = Array.isArray(body) ? body[0] : body;
if (!evt || !evt.payload) {
  return [
    {
      json: {
        error: "No Zoho event payload found",
        raw: item.json,
      },
    },
  ];
}

const payload = evt.payload;
const firstThread = payload.firstThread || null;

// Contact info can appear in payload.contact
const contact = payload.contact || {};
const attachments =
  (firstThread?.attachments || payload.descAttachments || []).map((a) => ({
    id: firstDefined(a.id, null),
    name: firstDefined(a.name, null),
    size: toIntMaybe(a.size),
    href: firstDefined(a.href, a.contentUrl, null),
    previewUrl: firstDefined(a.previewurl, a.previewUrl, null),
  }));

// Convenience fields for identity resolution
const requesterEmail = firstDefined(contact.email, payload.email, null);
let requesterDomain = null;
if (requesterEmail && requesterEmail.includes("@")) {
  requesterDomain = requesterEmail.split("@").pop().toLowerCase();
}

// Thread content: prefer summary; keep HTML too
const threadHtml = firstDefined(firstThread?.content, null);
const threadText = stripHtml(threadHtml);
const threadSummary = firstDefined(firstThread?.summary, threadText, null);

// Main normalized output
const normalized = {
  // Source / event
  source: "zoho_desk",
  eventType: firstDefined(evt.eventType, null), // e.g., Ticket_Add
  eventTimeMs: firstDefined(evt.eventTime, null),
  orgId: firstDefined(evt.orgId, item.json?.body?.orgId, null),

  // Ticket identifiers
  ticketId: firstDefined(payload.id, null),
  ticketNumber: firstDefined(payload.ticketNumber, null),
  departmentId: firstDefined(payload.departmentId, null),
  webUrl: firstDefined(payload.webUrl, null),

  // Ticket fields
  subject: firstDefined(payload.subject, null),
  status: firstDefined(payload.status, null),
  statusType: firstDefined(payload.statusType, null),
  channel: firstDefined(payload.channel, null),
  priority: firstDefined(payload.priority, null),
  category: firstDefined(payload.category, null),
  subCategory: firstDefined(payload.subCategory, null),
  classification: firstDefined(payload.classification, null),
  sentiment: firstDefined(payload.sentiment, null),

  // Times
  createdTime: firstDefined(payload.createdTime, null),
  modifiedTime: firstDefined(payload.modifiedTime, null),
  closedTime: firstDefined(payload.closedTime, null),
  dueDate: firstDefined(payload.dueDate, null),
  responseDueDate: firstDefined(payload.responseDueDate, null),
  customerResponseTime: firstDefined(payload.customerResponseTime, null),
  lastActivityTime: firstDefined(payload.lastActivityTime, null),

  // Contact / requester (identity resolution)
  contact: {
    id: firstDefined(contact.id, payload.contactId, null),
    firstName: firstDefined(contact.firstName, null),
    lastName: firstDefined(contact.lastName, null),
    phone: firstDefined(contact.phone, payload.phone, null),
    mobile: firstDefined(contact.mobile, null),
    email: requesterEmail,
    domain: requesterDomain,
    isSpam: firstDefined(contact.isSpam, payload.isSpam, null),
    type: firstDefined(contact.type, null),
    accountId: firstDefined(payload.accountId, contact.account?.id, null),
  },

  // Assignee (if any)
  assignee: payload.assignee
    ? {
        id: firstDefined(payload.assignee.id, payload.assigneeId, null),
        firstName: firstDefined(payload.assignee.firstName, null),
        lastName: firstDefined(payload.assignee.lastName, null),
        email: firstDefined(payload.assignee.email, null),
      }
    : {
        id: firstDefined(payload.assigneeId, null),
        firstName: null,
        lastName: null,
        email: null,
      },

  // First thread (useful for summarization/triage)
  firstThread: firstThread
    ? {
        id: firstDefined(firstThread.id, null),
        ticketId: firstDefined(firstThread.ticketId, payload.id, null),
        channel: firstDefined(firstThread.channel, null),
        direction: firstDefined(firstThread.direction, null), // "in" for customer
        visibility: firstDefined(firstThread.visibility, null),
        createdTime: firstDefined(firstThread.createdTime, null),
        contentType: firstDefined(firstThread.contentType, null),
        summary: threadSummary,
        contentHtml: threadHtml,
        contentText: threadText,
        hasAttach: firstDefined(firstThread.hasAttach, false),
        attachmentCount: toIntMaybe(firstThread.attachmentCount) ?? attachments.length,
        fromEmailAddress: firstDefined(firstThread.fromEmailAddress, null),
        to: firstDefined(firstThread.to, null),
        cc: firstDefined(firstThread.cc, null),
        author: firstThread.author
          ? {
              id: firstDefined(firstThread.author.id, null),
              name: firstDefined(firstThread.author.name, null),
              email: firstDefined(firstThread.author.email, null),
              type: firstDefined(firstThread.author.type, null),
            }
          : null,
      }
    : null,

  // Custom fields (both shapes exist in Zoho payloads)
  customFields: payload.customFields || {},
  cf: payload.cf || {},

  // Attachments (metadata + download href)
  attachments,

  // Counts
  counts: {
    threadCount: toIntMaybe(payload.threadCount),
    commentCount: toIntMaybe(payload.commentCount),
    taskCount: toIntMaybe(payload.taskCount),
    timeEntryCount: toIntMaybe(payload.timeEntryCount),
    followerCount: toIntMaybe(payload.followerCount),
    approvalCount: toIntMaybe(payload.approvalCount),
    attachmentCount: toIntMaybe(payload.attachmentCount) ?? attachments.length,
  },

  // Flags
  flags: {
    isOverDue: !!payload.isOverDue,
    isResponseOverdue: !!payload.isResponseOverdue,
    isSpam: !!payload.isSpam,
    isEscalated: !!payload.isEscalated,
    isTrashed: !!payload.isTrashed,
    isArchived: !!payload.isArchived,
    isDeleted: !!payload.isDeleted,
  },

  // Raw (optional - keep if you want audit trace; remove if too heavy)
  // raw: {
    // event: evt,
  // },
};

return [{ json: normalized }];

// ===== BUILD LLM REQUEST FOR ZOHO TICKET CLASSIFICATION =====
const zoho = $('Code in JavaScript1').first().json;
const dbConfig = $('Fetch Config by Domain1').first().json;

// Extract dynamic lists from DB (or use defaults if domain not found)
const hasConfig = !!dbConfig?.company_id;

const modules = hasConfig && Array.isArray(dbConfig.modules)
  ? dbConfig.modules.map(m => m.module_name).filter(Boolean)
  : ['Login/Sign Up', 'Language', 'Landing Page (Home)', 'My Health', 'Cash Claims',
     'Call Doctor Now', 'Appointment', 'AI Companion', 'Apps Sections and Functions',
     'Digital Twin', 'Wellness'];

const requestTypes = hasConfig && Array.isArray(dbConfig.request_types)
  ? dbConfig.request_types.map(rt => rt.request_type).filter(Boolean)
  : ['Incident', 'Service Request', 'Problem', 'Change Request'];

const slaConfigs = hasConfig && Array.isArray(dbConfig.sla_configs)
  ? dbConfig.sla_configs
  : [];

// Build priority context from SLA configs
let priorityContext = '';
if (slaConfigs.length > 0) {
  priorityContext = 'Available priorities with SLA:\n' +
    slaConfigs.map(s =>
      `- ${s.priority} (${s.priority_name}): Response ${s.response_hours}h, Resolution ${s.resolution_hours}h`
    ).join('\n');
} else {
  priorityContext = `Priority levels (assess based on impact and urgency):
- P1 (Critical): Complete system/app outage or total loss of service
- P2 (High): Major functionality impaired, core operations impacted
- P3 (Medium): Partial disruption affecting non-core functions
- P4 (Low): Minor issue with limited impact
- P5 (Very Low): Isolated issue with minimal impact`;
}

const systemPrompt = `You are an expert support ticket classifier for a healthcare app support system.

Your job is to analyze a new support ticket from an email and return a structured JSON profile.

Available modules: ${modules.join(', ')}

Request types: ${requestTypes.join(', ')}

${priorityContext}

Respond ONLY with valid JSON, no markdown, no explanation:
{
  "request_type": "<one of the request types listed above>",
  "case_type": "<brief case type label, e.g. 'Login Failure', 'Crash on Launch', 'Claim Submission Error'>",
  "priority": "<P1|P2|P3|P4|P5>",
  "sentiment": "positive|neutral|negative|frustrated|angry",
  "summary": "<1-2 sentence summary of the issue>",
  "module": "<best matching module from the list, or 'Unknown'>"
}`;

const emailContent = zoho.firstThread?.summary
  || zoho.firstThread?.contentText
  || zoho.subject
  || 'No content available';

const userMessage = `Email Subject: ${zoho.subject || 'No subject'}

Email Body:
${emailContent}

Sender: ${zoho.contact?.firstName || ''} ${zoho.contact?.lastName || ''} (${zoho.contact?.email || 'unknown'})
Domain: ${zoho.contact?.domain || 'unknown'}
Channel: ${zoho.channel || 'email'}
Zoho Priority: ${zoho.priority || 'Not set'}
Zoho Category: ${zoho.category || 'Not set'}`;

const requestBody = {
  temperature: 0.1,
  model: 'gpt-4.1',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

return [{
  json: {
    requestBody: JSON.stringify(requestBody),
    _zoho: zoho,
    _dbConfig: dbConfig,
    _hasConfig: hasConfig,
    _slaConfigs: slaConfigs
  }
}];

// ===== PARSE LLM RESPONSE + ENRICH ZOHO DATA FOR CLICKUP =====
const llmResponse = $input.first().json;
const prev = $('Build Zoho LLM Request1').first().json;
const zoho = prev._zoho;
const dbConfig = prev._dbConfig;
const hasConfig = prev._hasConfig;
const slaConfigs = prev._slaConfigs || [];

// Parse LLM response
let profile;
try {
  const content = llmResponse.choices?.[0]?.message?.content || '{}';
  const cleaned = content.replace(/```json|```/g, '').trim();
  profile = JSON.parse(cleaned);
} catch (e) {
  profile = {
    request_type: 'Incident',
    case_type: 'Availability',
    priority: 'P3',
    sentiment: 'neutral',
    summary: zoho.subject || 'New ticket from Zoho',
    module: 'Unknown'
  };
}

const priority = profile.priority || 'P3';

// Map priority to ClickUp priority integer (1=Urgent, 2=High, 3=Normal, 4=Low)
const clickupPriorityMap = { 'P1': 1, 'P2': 2, 'P3': 3, 'P4': 4, 'P5': 4 };
const clickupPriority = clickupPriorityMap[priority] || 3;

// --- EXACT CLICKUP DROPDOWN UUID MAPPING ---
// Using exact Option IDs from your ClickUp workspace schema
const requestTypeMap = {
  "Incident": "037ea1a4-88f0-43d0-9bd9-386fc385aaac",
