};

const caseTypeMap = {
  "Availability": "71924ef3-bd27-46f4-af4b-986f21db3b9d",
  "Core Function": "75b4337c-75d0-46b8-a849-618e19f1fbdd",
  "Integration": "7d6f15a1-2bef-4989-a5c4-9d79adbc28b1",
  "Data Integrity": "d960b7a3-005c-4b72-a64d-a438fd6980ee",
  "Performance": "7c02067a-2703-4dd2-80c7-53a412b52302",
  "Stability": "2a69eb54-c762-44da-bb36-41a568dcd10a",
  "Security": "9412cc67-a469-436f-a875-617ddedf28c8",
  "UI / UX": "f6116b75-c6ca-452c-9737-a4859b211495",
  "Support": "4ea73a69-a682-41ec-96e3-3ffb32fb45cd",
  "Access": "1cd65a2e-89fa-4771-be97-1f9fe6002a1d",
  "Problem Record": "11115504-b918-4ad9-addb-49b02973978a",
  "Enhancement": "6c05810f-baba-4bc8-aed5-efa9fb2ce86e",

  // Fallbacks for LLM hallucinations based on previous runs
  "Major Outage": "71924ef3-bd27-46f4-af4b-986f21db3b9d", // Maps to Availability
  "Complete App Outage": "71924ef3-bd27-46f4-af4b-986f21db3b9d", // Maps to Availability
  "Uncategorized": "4ea73a69-a682-41ec-96e3-3ffb32fb45cd" // Default to Support if completely lost
};

// --- BUILD JSON ARRAY FOR CLICKUP CUSTOM FIELDS ---
const clickupCustomFields = [];

// Resolve Request Type
const resolvedRequestType = requestTypeMap[profile.request_type] || requestTypeMap["Incident"];
clickupCustomFields.push({
  "id": "83ff465c-0075-495c-aeb8-7db8cc56110a",
  "value": resolvedRequestType
});

// Resolve Case Type
const resolvedCaseType = caseTypeMap[profile.case_type] || caseTypeMap["Availability"];

clickupCustomFields.push({
  "id": "de899780-bc87-4ec2-ba94-fe01690ab330",
  "value": resolvedCaseType
});

// Project = MedGulf (always tag so team can filter in shared ClickUp workspace)
clickupCustomFields.push({
  "id": "c75f543d-799e-4d4e-80c9-193cc1c765bc",
  "value": "c6194728-c763-4cb8-8ee6-730cd855239e"
});

// Module field — map Cortex module name to ClickUp option UUID
const moduleMap = {
  'Login/Sign Up': '2213d3ff-ac80-46af-ac6e-c1350a686bfe',
  'Login': '2213d3ff-ac80-46af-ac6e-c1350a686bfe',
  'Landing Page (Home)': '00b6c134-d756-47b0-b3b6-14bab4b2dad1',
  'Landing Page': '00b6c134-d756-47b0-b3b6-14bab4b2dad1',
  'My Health': 'd88061d1-19fd-4d6f-94b1-fee6c942df5d',
  'Cash Claims': '4cd06e13-0957-492c-af32-bbf4d563d7c8',
  'Claims': '4cd06e13-0957-492c-af32-bbf4d563d7c8',
  'Call Doctor Now': '4255761e-2020-4225-acc8-e3a3460d7f42',
  'Appointment': 'ba8a07e0-ca30-4e8c-a593-d55ae971c035',
  'AI Companion': '78edd917-bdda-4f97-95a3-a22f7c7552ad',
  'Digital Twin': '0567e8ea-bc92-4e88-a48b-47fd0859fb81',
  'Wellness': '924fde6f-f563-49ed-8ec3-3ca7ef430257',
  'Support Center': 'ce9004b2-41b2-41cc-9a3c-4e8841ca64da',
  'Apps Sections and Functions': 'ce9004b2-41b2-41cc-9a3c-4e8841ca64da',
  'Language': 'ce9004b2-41b2-41cc-9a3c-4e8841ca64da'
};
const moduleUUID = moduleMap[profile.module] || moduleMap['Support Center'];
clickupCustomFields.push({
  "id": "7543a2bd-1322-407f-b171-9295dca96a5b",
  "value": moduleUUID
});


// Build enriched task description
const contactName = [zoho.contact?.firstName, zoho.contact?.lastName].filter(Boolean).join(' ') || 'Unknown';
const emailContent = zoho.firstThread?.summary || zoho.firstThread?.contentText || 'No content';

const description = `**AI Classification:**\nPriority: ${priority} | Request Type: ${profile.request_type} | Module: ${profile.module}\nCase Type: ${profile.case_type} | Sentiment: ${profile.sentiment}\n\n**Summary:** ${profile.summary}\n\n---\n\n**Ticket Details:**\nRaised by: ${contactName}\nEmail: ${zoho.contact?.email || 'Unknown'}\nDomain: ${zoho.contact?.domain || 'Unknown'}\nChannel: ${zoho.channel || 'email'}\nZoho Ticket: #${zoho.ticketNumber || 'N/A'}\n\n**Email Subject:** ${zoho.subject || 'No subject'}\n\n**Email Content:**\n${emailContent}\n\n${zoho.attachments?.length > 0 ? `\n**Attachments:** ${zoho.attachments.map(a => `[${a.name}](${a.href})`).join(', ')}` : ''}\n${hasConfig ? `\n**Matched Company:** ${dbConfig.company_name} (${dbConfig.company_code})` : '**Company:** Could not resolve from domain'}`;

// Determine assignee based on company config
const defaultAssignee = 87796566; // Asif K - L1

// Pass everything through to Create a task
return [{
  json: {
    ...zoho,
    _enriched: true,
    _profile: profile,
    _priority: priority,
    _clickupPriority: clickupPriority,
    _customFieldsJSON: clickupCustomFields, // Correct formatted array with UUIDs
    _description: description,
    _assignee: defaultAssignee,
    _companyName: hasConfig ? dbConfig.company_name : null,
    _solutionId: hasConfig ? dbConfig.solution_id : null,
    _companyId: hasConfig ? dbConfig.company_id : null,
    _requestType: profile.request_type,
    _caseType: profile.case_type,
    _module: profile.module,
    _sentiment: profile.sentiment,
    _summary: profile.summary,
    _slaConfigs: slaConfigs,
    _dbConfig: dbConfig || {}
  }
}];

// Parse incoming Zoho Thread_Add webhook payload
const item = items[0] || {};
const body = item.json?.body;
const evt = Array.isArray(body) ? body[0] : body;
if (!evt || !evt.payload) {
  return [{ json: { _skip: true, reason: 'No payload' } }];
}

const payload = evt.payload;
const thread = payload.thread || payload.firstThread || null;
if (!thread) {
  return [{ json: { _skip: true, reason: 'No thread in payload' } }];
}

function stripHtml(html) {
  if (!html) return null;
  return String(html).replace(/<style[sS]*?</style>/gi, ' ')
    .replace(/<script[sS]*?</script>/gi, ' ')
    .replace(/</?[^>]+(>|$)/g, ' ').replace(/s+/g, ' ').trim();
}

const contentText = stripHtml(thread.content || thread.contentHtml) || thread.summary || '';
const contactEmail = payload.contact?.email || thread.fromEmailAddress || null;
const contactName = [payload.contact?.firstName, payload.contact?.lastName].filter(Boolean).join(' ') || contactEmail;
const zohoTicketNumber = String(payload.ticketNumber || payload.id || '');

return [{
  json: {
    zoho_ticket_number: zohoTicketNumber,
    thread_id: String(thread.id || ''),
    direction: thread.direction || 'in',
    content_text: contentText.substring(0, 5000),
    content_html: (thread.content || '').substring(0, 10000),
    actor_email: contactEmail,
    actor_name: contactName,
    created_at: thread.createdTime || new Date().toISOString(),
    has_attachments: !!(thread.hasAttach || (thread.attachmentCount > 0)),
    _skip: !zohoTicketNumber
  }
}];
